// 三载体一致:纯 JS 数值变换,零 DOM/CSS/uplink/shadow 足迹;default 导出
import FFT from 'https://cdn.jsdelivr.net/npm/fft.js@4/+esm';
const size = data.samples.length;              // 必须是 2 的幂且 >1
const fft = new FFT(size);
const out = fft.createComplexArray();          // 长度 2*size
fft.realTransform(out, data.samples);          // 实数信号 → 频谱(填满前半非冗余部分)
const mag = [];                                // 0..Nyquist 各 bin 幅值
for (let k = 0; k <= size / 2; k++) mag.push(Math.hypot(out[2*k], out[2*k+1]));
// 频率轴(可选):const freq = k => k * (data.sampleRate ?? size) / size;
